        ["Debug Detect Target"] = "\uB514\uBC84\uADF8 \uC778\uC2DD \uB300\uC0C1",
        ["Choose the top grouped debug target."] = "\uC0C1\uB2E8 \uAC00\uB85C\uD615 \uB514\uBC84\uADF8 \uB300\uC0C1\uC744 \uC120\uD0DD\uD558\uC138\uC694.",
        ["Top Grouped Debug Target"] = "\uC0C1\uB2E8 \uAC00\uB85C\uD615 \uB514\uBC84\uADF8 \uB300\uC0C1",
        ["No matching quickslot section pattern was found in the selected area. Log: {0}"] = "\uC120\uD0DD\uD55C \uC601\uC5ED\uC5D0\uC11C \uC77C\uCE58\uD558\uB294 \uD035\uC2AC\uB86F \uC139\uC158 \uD328\uD134\uC744 \uCC3E\uC9C0 \uBABB\uD588\uC2B5\uB2C8\uB2E4. \uB85C\uADF8: {0}",
        ["Added {0}: {1} slots, slot {2}x{3}px, gap X {4}px, gap Y {5}px, large gap {6}px. Log: {7}"] = "{0} \uCD94\uAC00 \uC644\uB8CC: {1}\uAC1C \uC2AC\uB86F, \uC2AC\uB86F {2}x{3}px, X \uAC04\uACA9 {4}px, Y \uAC04\uACA9 {5}px, \uD070 \uAC04\uACA9 {6}px. \uB85C\uADF8: {7}",
        ["Debug detect finished: exact {0}/{1}, detected {2}/{3}. Log: {4}"] = "\uB514\uBC84\uADF8 \uC778\uC2DD \uC644\uB8CC: \uC815\uD655 \uC77C\uCE58 {0}/{1}, \uC778\uC2DD {2}/{3}. \uB85C\uADF8: {4}",
        ["Capture and detect candidates first."] = "\uBA3C\uC800 \uCEA1\uCCD0\uC640 \uD6C4\uBCF4 \uC778\uC2DD\uC744 \uC2E4\uD589\uD558\uC138\uC694.",
        ["No checked candidates. Check slots to place first."] = "\uCCB4\uD06C\uB41C \uD6C4\uBCF4\uAC00 \uC5C6\uC2B5\uB2C8\uB2E4. \uBA3C\uC800 \uBC30\uCE58\uD560 \uC2AC\uB86F\uC744 \uCCB4\uD06C\uD558\uC138\uC694.",
        ["Selected candidates are already on the overlay."] = "\uC120\uD0DD\uD55C \uD6C4\uBCF4\uB294 \uC774\uBBF8 \uC624\uBC84\uB808\uC774\uC5D0 \uC788\uC2B5\uB2C8\uB2E4.",
        ["Placed {0} slots. Open Manage Layout to arrange them."] = "{0}\uAC1C \uC2AC\uB86F\uC744 \uBC30\uCE58\uD588\uC2B5\uB2C8\uB2E4. Manage Layout\uC744 \uC5F4\uC5B4 \uC815\uB82C\uD558\uC138\uC694.",
        ["Added {0} slot(s) to overlay. Total {1}."] = "\uC624\uBC84\uB808\uC774\uC5D0 {0}\uAC1C \uC2AC\uB86F\uC744 \uCD94\uAC00\uD588\uC2B5\uB2C8\uB2E4. \uCD1D {1}\uAC1C\uC785\uB2C8\uB2E4.",
        ["Selected all {0} candidates."] = "\uD6C4\uBCF4 {0}\uAC1C\uB97C \uBAA8\uB450 \uC120\uD0DD\uD588\uC2B5\uB2C8\uB2E4.",
        ["Deselected all {0} candidates."] = "\uD6C4\uBCF4 {0}\uAC1C\uC758 \uC120\uD0DD\uC744 \uBAA8\uB450 \uD574\uC81C\uD588\uC2B5\uB2C8\uB2E4.",
        ["Capture the game window before adding a manual candidate."] = "\uC218\uB3D9 \uD6C4\uBCF4\uB97C \uCD94\uAC00\uD558\uAE30 \uC804\uC5D0 \uAC8C\uC784 \uCC3D\uC744 \uCEA1\uCCD0\uD558\uC138\uC694.",
        ["Manual candidate added. Drag it over the target quickslot."] = "\uC218\uB3D9 \uD6C4\uBCF4\uB97C \uCD94\uAC00\uD588\uC2B5\uB2C8\uB2E4. \uB300\uC0C1 \uD035\uC2AC\uB86F \uC704\uB85C \uB4DC\uB798\uADF8\uD558\uC138\uC694.",
        ["Capture the game window before resizing a candidate."] = "\uD6C4\uBCF4 \uD06C\uAE30\uB97C \uBCC0\uACBD\uD558\uAE30 \uC804\uC5D0 \uAC8C\uC784 \uCC3D\uC744 \uCEA1\uCCD0\uD558\uC138\uC694.",
        ["Select exactly one candidate before applying slot size."] = "\uC2AC\uB86F \uD06C\uAE30\uB97C \uC801\uC6A9\uD558\uAE30 \uC804\uC5D0 \uD6C4\uBCF4 \uD558\uB098\uB9CC \uC120\uD0DD\uD558\uC138\uC694.",
        ["The resized candidate would exceed the captured image bounds."] = "\uBCC0\uACBD\uB41C \uD6C4\uBCF4 \uD06C\uAE30\uAC00 \uCEA1\uCCD0 \uC774\uBBF8\uC9C0 \uBC94\uC704\uB97C \uBC97\uC5B4\uB0A9\uB2C8\uB2E4.",
        ["Applied candidate size {0}x{1} to #{2}."] = "#{2} \uD6C4\uBCF4\uC5D0 {0}x{1} \uD06C\uAE30\uB97C \uC801\uC6A9\uD588\uC2B5\uB2C8\uB2E4.",
        ["Capture the game window before adding a quickslot section."] = "\uD035\uC2AC\uB86F \uC139\uC158\uC744 \uCD94\uAC00\uD558\uAE30 \uC804\uC5D0 \uAC8C\uC784 \uCC3D\uC744 \uCEA1\uCCD0\uD558\uC138\uC694.",
        ["Select or add the top-left slot of the section first."] = "\uBA3C\uC800 \uC139\uC158\uC758 \uC67C\uCABD \uC704 \uC2AC\uB86F\uC744 \uC120\uD0DD\uD558\uAC70\uB098 \uCD94\uAC00\uD558\uC138\uC694.",
        ["Generated {0} from #{1}. Adjust small/large gap sliders to align the section."] = "#{1}\uC5D0\uC11C {0}\uC744 \uC0DD\uC131\uD588\uC2B5\uB2C8\uB2E4. \uC791\uC740/\uD070 \uAC04\uACA9 \uC2AC\uB77C\uC774\uB354\uB85C \uC139\uC158\uC744 \uB9DE\uCD94\uC138\uC694.",
        ["No section is selected."] = "\uC120\uD0DD\uB41C \uC139\uC158\uC774 \uC5C6\uC2B5\uB2C8\uB2E4.",
