        ["Selected section {0}."] = "\uC139\uC158 {0}\uC744 \uC120\uD0DD\uD588\uC2B5\uB2C8\uB2E4.",
        ["No selected candidates to delete."] = "\uC0AD\uC81C\uD560 \uC120\uD0DD \uD6C4\uBCF4\uAC00 \uC5C6\uC2B5\uB2C8\uB2E4.",
        ["Deleted {0} selected candidates."] = "\uC120\uD0DD \uD6C4\uBCF4 {0}\uAC1C\uB97C \uC0AD\uC81C\uD588\uC2B5\uB2C8\uB2E4.",
        ["Candidate list cleared."] = "\uD6C4\uBCF4 \uBAA9\uB85D\uC744 \uC9C0\uC6E0\uC2B5\uB2C8\uB2E4.",
        ["Adjusted {0}: gap X {1}px, gap Y {2}px, large gap {3}px."] = "{0} \uC870\uC815 \uC644\uB8CC: X \uAC04\uACA9 {1}px, Y \uAC04\uACA9 {2}px, \uD070 \uAC04\uACA9 {3}px.",
        ["Nudged {0} candidate(s) by 1px."] = "\uD6C4\uBCF4 {0}\uAC1C\uB97C 1px \uC774\uB3D9\uD588\uC2B5\uB2C8\uB2E4.",
