        ["No candidate edit to redo."] = "\uB2E4\uC2DC \uC2E4\uD589\uD560 \uD6C4\uBCF4 \uD3B8\uC9D1\uC774 \uC5C6\uC2B5\uB2C8\uB2E4.",
        ["Candidate edit redone."] = "\uD6C4\uBCF4 \uD3B8\uC9D1\uC744 \uB2E4\uC2DC \uC2E4\uD589\uD588\uC2B5\uB2C8\uB2E4.",
        ["Stop the overlay before opening Manage Layout."] = "Manage Layout\uC744 \uC5F4\uAE30 \uC804\uC5D0 \uC624\uBC84\uB808\uC774\uB97C \uC911\uC9C0\uD558\uC138\uC694.",
