        ["Layout editor closed. Overlay settings updated."] = "\uB808\uC774\uC544\uC6C3 \uC5D0\uB514\uD130\uAC00 \uB2EB\uD614\uC2B5\uB2C8\uB2E4. \uC624\uBC84\uB808\uC774 \uC124\uC815\uC774 \uC5C5\uB370\uC774\uD2B8\uB418\uC5C8\uC2B5\uB2C8\uB2E4.",
        ["Overlay layout cleared."] = "\uC624\uBC84\uB808\uC774 \uB808\uC774\uC544\uC6C3\uC744 \uC9C0\uC6E0\uC2B5\uB2C8\uB2E4.",
