        ["No slots are placed on the overlay canvas."] = "\uC624\uBC84\uB808\uC774 \uCE94\uBC84\uC2A4\uC5D0 \uBC30\uCE58\uB41C \uC2AC\uB86F\uC774 \uC5C6\uC2B5\uB2C8\uB2E4.",
        ["Overlay click-through configuration failed: {0}"] = "\uC624\uBC84\uB808\uC774 \uD074\uB9AD \uD1B5\uACFC \uC124\uC815 \uC2E4\uD328: {0}",
