        ["Overlay started ({0}, {1}, {2}). Stop hotkey: {3}"] = "\uC624\uBC84\uB808\uC774 \uC2DC\uC791\uB428 ({0}, {1}, {2}). \uC911\uC9C0 \uB2E8\uCD95\uD0A4: {3}",
        ["Overlay start failed: {0}"] = "\uC624\uBC84\uB808\uC774 \uC2DC\uC791 \uC2E4\uD328: {0}",
        ["Overlay stopped."] = "\uC624\uBC84\uB808\uC774\uAC00 \uC911\uC9C0\uB418\uC5C8\uC2B5\uB2C8\uB2E4.",
        ["Live overlay refresh failed: {0}"] = "\uC2E4\uC2DC\uAC04 \uC624\uBC84\uB808\uC774 \uAC31\uC2E0 \uC2E4\uD328: {0}",
        ["Invalid hotkey. Use a format like Ctrl+Shift+F8."] = "\uC798\uBABB\uB41C \uB2E8\uCD95\uD0A4\uC785\uB2C8\uB2E4. Ctrl+Shift+F8 \uAC19\uC740 \uD615\uC2DD\uC744 \uC0AC\uC6A9\uD558\uC138\uC694.",
        ["Stop hotkey registration failed: {0}"] = "\uC911\uC9C0 \uB2E8\uCD95\uD0A4 \uB4F1\uB85D \uC2E4\uD328: {0}",
